import { BrowserRouter, Routes, Route } from "react-router-dom";
import Home from "./pages/Home";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Dashboard from "./pages/Dashboard";
import Navbar from "./components/Navbar";
import Books from "./pages/Books";
import LibrarianInventory from "./pages/LibrarianInventory";
import FineCalculator from "./pages/FineCalculator";
import Reports from "./pages/Reports";
import CategoryBooks from "./pages/CategoryBooks";
import BorrowedBooks from "./pages/BorrowedBooks";
import BookDetails from "./pages/BooksDetails";
import LibrarianDashboard from "./pages/LibrarianDashboard";
import Auth from "./pages/Auth";
import StudentDashboard from "./pages/StudentDashboard";
<Route path="/mybooks" element={<MyBooks />} />





function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/books" element={<Books />} />
        <Route path="/inventory" element={<LibrarianInventory />} />
        <Route path="/fine" element={<FineCalculator />} />
        <Route path="/reports" element={<Reports />} />
        <Route path="/category/:name" element={<CategoryBooks />} />
        <Route path="/book/:title/:author/:cover" element={<BookDetails />} />
        <Route path="/borrowed" element={<BorrowedBooks />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/librarian" element={<LibrarianDashboard />} />
        <Route path="/auth" element={<Auth />} />
        <Route path="/student-dashboard" element={<StudentDashboard />} />
        <Route path="/librarian-dashboard" element={<LibrarianDashboard />} />




<Route path="/books" element={<Books />} />
<Route path="/category/:name" element={<CategoryBooks />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
